// 格式化AI Agent的输出，使其适合网站显示
const inputData = $input.all();
const results = [];

// 找到正确的AI Agent输出
let correctOutput = null;
let workflowType = 'code';

for (const item of inputData) {
  const data = item.json;

  // 检查是否有AI Agent的输出
  if (data.output) {
    // 根据workflowType和route信息判断这是否是正确的输出
    if (data.workflowType === 'code' || data.workflowType === 'quick') {
      // 代码生成请求 - 只处理包含C++代码的输出
      if (data.output.includes('#include') || data.output.includes('FOVI') || data.output.includes('DIO_V3')) {
        correctOutput = data.output;
        workflowType = data.workflowType;
        break;
      }
    } else if (data.workflowType === 'plan') {
      // 测试方案生成请求 - 只处理包含测试方案的输出
      if (data.output.includes('测试方案') || data.output.includes('测试向量') || data.output.includes('VOH/VOL')) {
        correctOutput = data.output;
        workflowType = data.workflowType;
        break;
      }
    }
  }
}

// 如果没有找到正确的输出，使用第一个有输出的数据
if (!correctOutput) {
  for (const item of inputData) {
    const data = item.json;
    if (data.output) {
      correctOutput = data.output;
      workflowType = data.workflowType || 'code';
      break;
    }
  }
}

if (correctOutput) {
  // 根据workflowType确定消息类型
  let message = '处理完成';
  if (workflowType === 'code' || workflowType === 'quick') {
    message = '测试代码生成完成';
  } else if (workflowType === 'plan') {
    message = '测试方案生成完成';
  }

  const formattedOutput = {
    success: true,
    timestamp: new Date().toISOString(),
    workflowType: workflowType,
    output: correctOutput,
    message: message,
    status: 'completed'
  };

  results.push({ json: formattedOutput });
} else {
  // 没有找到有效输出
  const errorOutput = {
    success: false,
    timestamp: new Date().toISOString(),
    workflowType: 'unknown',
    output: null,
    message: '未找到有效的AI Agent输出',
    error: 'No valid output found',
    status: 'error'
  };

  results.push({ json: errorOutput });
}

return results;

// 路由节点：根据工作流类型选择不同的处理方式
const inputData = $input.all();
const results = [];

for (const item of inputData) {
  const data = item.json;

  // 根据工作流类型设置路由信息
  if (data.workflowType === 'code' || data.workflowType === 'quick') {
    // 测试代码生成工作流
    results.push({
      json: {
        ...data,
        route: 'code_generation',
        targetAgent: 'AI Agent'
      }
    });
  } else if (data.workflowType === 'plan') {
    // 测试方案生成工作流
    results.push({
      json: {
        ...data,
        route: 'test_plan',
        targetAgent: 'AI Agent1'
      }
    });
  } else {
    // 默认使用代码生成工作流
    results.push({
      json: {
        ...data,
        route: 'code_generation',
        targetAgent: 'AI Agent',
        workflowType: 'code'
      }
    });
  }
}

return results;

// 错误处理节点
const inputData = $input.all();
const results = [];

for (const item of inputData) {
  try {
    const data = item.json;

    // 检查是否有错误
    if (data.error || data.message?.includes('error')) {
      const errorResponse = {
        success: false,
        timestamp: new Date().toISOString(),
        workflowType: data.workflowType || 'unknown',
        output: null,
        message: '工作流执行失败',
        error: data.error || data.message,
        status: 'error'
      };

      results.push({ json: errorResponse });
    } else {
      // 正常数据直接传递
      results.push({ json: data });
    }
  } catch (error) {
    // 捕获处理过程中的错误
    const errorResponse = {
      success: false,
      timestamp: new Date().toISOString(),
      workflowType: 'unknown',
      output: null,
      message: '数据处理失败',
      error: error.message,
      status: 'error'
    };

    results.push({ json: errorResponse });
  }
}

return results;
